/*==============================================================*/
/* Table: CBTPRE                                                */
/*==============================================================*/
CREATE TABLE CBTPRE
(
    ID_CBTPRE_CODE       INT NOT NULL AUTO_INCREMENT,
    CBTPRE_COLOR_MODE    VARCHAR(16) NOT NULL,
    CBTPRE_MENU_MODE     VARCHAR(16) NOT NULL,
    CBTPRE_MENU_THEME    VARCHAR(16) NOT NULL,
    CBTPRE_TOPBAR_MODE   VARCHAR(16) NOT NULL,
    CBTPRE_COLOR         VARCHAR(16) NOT NULL,
    CBTPRE_VALID_FROM    TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    CBTPRE_VALID_TO      TIMESTAMP,
    CBTPRE_CREATED_BY    VARCHAR(16),
    CBTPRE_UPDATED_BY    VARCHAR(16),
    CBTPRE_CREATED_AT    TIMESTAMP NOT NULL DEFAULT '0000-00-00 00:00:00',
    CBTPRE_UPDATED_AT    TIMESTAMP NOT NULL DEFAULT '0000-00-00 00:00:00',
    PRIMARY KEY (ID_CBTPRE_CODE)
)
    COMMENT 'PREFERENCIAS USUARIO';

/*==============================================================*/
/* Table: CBTUSE                                                */
/*==============================================================*/
CREATE TABLE CBTUSE
(
    ID_CBTUSE_CODE       VARCHAR(64) NOT NULL,
    XID_CBTPRE_CODE      INT,
    CBTUSE_USERNAME      VARCHAR(16) NOT NULL,
    CBTUSE_PHOTO         VARCHAR(64),
    CBTUSE_PHONE         VARCHAR(16),
    CBTUSE_ADDRESS       VARCHAR(64),
    CBTUSE_VALID_FROM    TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    CBTUSE_VALID_TO      TIMESTAMP,
    CBTUSE_CREATED_BY    VARCHAR(16),
    CBTUSE_UPDATED_BY    VARCHAR(16),
    CBTUSE_CREATED_AT    TIMESTAMP NOT NULL DEFAULT '0000-00-00 00:00:00',
    CBTUSE_UPDATED_AT    TIMESTAMP NOT NULL DEFAULT '0000-00-00 00:00:00',
    PRIMARY KEY (ID_CBTUSE_CODE)
)
    COMMENT 'USUARIO';


ALTER TABLE CBTUSE ADD CONSTRAINT XID_CBTPRE_CODE_XID_CBTPRE_CODE FOREIGN KEY (XID_CBTPRE_CODE)
    REFERENCES CBTPRE (ID_CBTPRE_CODE);


